"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { cn } from "@/lib/utils";
import {
  LayoutDashboard,
  Flag,
  Beaker,
  BrainCircuit,
  Activity,
  Settings,
} from "lucide-react";
import { motion } from "framer-motion";

import { UserButton, useUser } from "@clerk/nextjs";

const sidebarNavItems = [
  {
    title: "Dashboard",
    href: "/",
    icon: LayoutDashboard,
  },
  {
    title: "AI Decisions",
    href: "/ai-decisions",
    icon: BrainCircuit,
  },
  {
    title: "Control",
    href: "/flags",
    icon: Flag,
  },
  {
    title: "Monitoring",
    href: "/monitoring",
    icon: Beaker,
  },
  {
    title: "Integrations",
    href: "/integrations",
    icon: Activity,
  },
  {
    title: "Settings",
    href: "/settings",
    icon: Settings,
  },
];

export function Sidebar() {
  const pathname = usePathname();
  const { user } = useUser();

  return (
    <aside className="hidden md:flex w-64 flex-col border-r border-border/40 bg-card/40 backdrop-blur-xl h-full shadow-lg">
      <div className="p-6 pb-4">
        <Link href="/" className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary text-primary-foreground font-bold shadow-[0_0_20px_rgba(139,92,246,0.3)]">
            F
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-lg leading-none tracking-tight text-glow">FeatureFlag</span>
            <span className="text-[10px] text-muted-foreground mt-1 font-medium leading-tight opacity-80">
              Autonomous Intelligence
            </span>
          </div>
        </Link>
      </div>

      <nav className="flex-1 space-y-1.5 px-4 py-4 custom-scrollbar overflow-y-auto">
        {sidebarNavItems.map((item) => {
          const isActive = pathname === item.href || (item.href !== "/" && pathname.startsWith(item.href + "/"));
          return (
            <Link
              key={item.href}
              href={item.href}
              className={cn(
                "group relative flex items-center gap-3 rounded-md px-3 py-2.5 text-sm font-medium transition-all duration-300",
                isActive
                  ? "text-primary bg-primary/10"
                  : "text-muted-foreground hover:bg-muted/50 hover:text-foreground"
              )}
            >
              {isActive && (
                <motion.div
                  layoutId="sidebar-active-indicator"
                  className="absolute left-0 top-1.5 bottom-1.5 w-1 rounded-r-md bg-primary shadow-[0_0_10px_rgba(139,92,246,0.5)]"
                  initial={false}
                  transition={{ type: "spring", stiffness: 300, damping: 30 }}
                />
              )}
              <item.icon className={cn("h-4 w-4 relative z-10 transition-transform duration-300", isActive ? "scale-110" : "group-hover:scale-110")} />
              <span className="relative z-10 tracking-wide">{item.title}</span>
            </Link>
          );
        })}
      </nav>

      <div className="p-4 border-t border-border/40 mt-auto">
        <div className="flex items-center gap-3 rounded-lg px-3 py-2 hover:bg-muted/50 transition-all border border-transparent hover:border-border/50">
          <UserButton appearance={{ elements: { avatarBox: "h-8 w-8 rounded-md" } }} />
          <div className="flex flex-col overflow-hidden">
            <span className="text-sm font-semibold truncate">{user?.fullName || "Operator"}</span>
            <span className="text-[10px] text-muted-foreground truncate uppercase tracking-wider font-bold">{user?.publicMetadata?.role as string || "Engineer"}</span>
          </div>
        </div>
      </div>
    </aside>
  );
}
